const body = $json.body ?? $json;
const adapter_warnings = [];

function hasValue(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

function cleanString(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function cleanLower(value) {
  return cleanString(value).toLowerCase();
}

function firstValue(...values) {
  for (const value of values) {
    if (hasValue(value)) return cleanString(value);
  }
  return "";
}

function toBoolean(value, fallback = false) {
  if (value === undefined || value === null || cleanString(value) === "") return fallback;
  if (typeof value === "boolean") return value;
  if (typeof value === "string") {
    const normalized = value.toLowerCase().trim();
    if (["true", "yes", "1", "y"].includes(normalized)) return true;
    if (["false", "no", "0", "n"].includes(normalized)) return false;
  }
  return Boolean(value);
}

function toNumber(value) {
  const numberValue = Number(value);
  return Number.isFinite(numberValue) ? numberValue : null;
}

function secondsBetween(start, end) {
  const startMs = Date.parse(cleanString(start));
  const endMs = Date.parse(cleanString(end));
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs) || endMs < startMs) return null;
  return Math.round((endMs - startMs) / 1000);
}

function transcriptExcerpt(value) {
  const transcript = cleanString(value);
  if (transcript.length <= 240) return transcript;
  return transcript.slice(0, 237) + "...";
}

function getRetellDuration(call) {
  const directSeconds = toNumber(call.call_duration_seconds ?? call.duration_seconds);
  if (directSeconds !== null) return directSeconds;

  const durationMs = toNumber(call.duration_ms);
  if (durationMs !== null) return Math.round(durationMs / 1000);

  return secondsBetween(
    call.call_started_at ?? call.started_at ?? call.start_timestamp,
    call.call_ended_at ?? call.ended_at ?? call.end_timestamp
  );
}

const isRetellStyle = Boolean(
  body &&
  typeof body === "object" &&
  body.call &&
  typeof body.call === "object" &&
  (
    hasValue(body.event) ||
    cleanString(body.provider).includes("retell") ||
    body.call.analysis ||
    body.call.call_analysis ||
    body.call.caller
  )
);

let source_provider = "native_synthetic";
let adapter_status = "native_passthrough";
let original_event_type = "";
let normalized = body;

if (isRetellStyle) {
  const retellCall = body.call ?? {};
  const analysis = retellCall.analysis ?? retellCall.call_analysis ?? body.call_analysis ?? {};
  const caller = retellCall.caller ?? {};

  source_provider = "retell_style_synthetic";
  original_event_type = cleanString(body.event);

  const transcript = cleanString(
    retellCall.transcript ??
    retellCall.transcript_text ??
    analysis.transcript
  );

  let summary = cleanString(
    retellCall.summary ??
    analysis.call_summary ??
    analysis.summary
  );

  const detectedIntent = firstValue(
    analysis.detected_intent,
    analysis.intent,
    retellCall.call_intent
  );

  let detectedUrgency = firstValue(
    analysis.detected_urgency,
    analysis.urgency,
    retellCall.urgency
  );

  const callbackRaw = analysis.callback_requested ?? retellCall.callback_requested;
  const callbackRequested = toBoolean(callbackRaw, false);
  const preferredCallbackTime = firstValue(
    analysis.preferred_callback_time,
    retellCall.preferred_callback_time
  );

  if (!hasValue(retellCall.call_id ?? retellCall.id ?? body.call_id)) {
    adapter_warnings.push("Missing call_id; validation should mark payload invalid.");
  }

  if (!hasValue(caller.name ?? retellCall.caller_name ?? analysis.caller_name)) {
    adapter_warnings.push("Missing caller name; preserving available caller identity fields.");
  }

  if (!hasValue(caller.phone ?? retellCall.caller_phone)) {
    adapter_warnings.push("Missing caller phone; using empty string for normalized field.");
  }

  if (!hasValue(transcript)) {
    adapter_warnings.push("Missing transcript; downstream validation requires summary, intent, or transcript.");
  }

  if (!hasValue(summary) && hasValue(transcript)) {
    summary = transcriptExcerpt(transcript);
    adapter_warnings.push("Missing summary; used transcript excerpt fallback.");
  }

  if (!hasValue(summary)) {
    adapter_warnings.push("Missing summary; downstream validation requires transcript or intent.");
  }

  if (!hasValue(detectedIntent)) {
    adapter_warnings.push("Missing intent; classifier will infer from summary or transcript.");
  }

  if (!hasValue(detectedUrgency)) {
    detectedUrgency = "low";
    adapter_warnings.push("Missing urgency; defaulted to low.");
  }

  if (!hasValue(callbackRaw)) {
    adapter_warnings.push("Missing callback_requested; defaulted to false.");
  }

  if (callbackRequested && !hasValue(preferredCallbackTime)) {
    adapter_warnings.push("Callback requested but preferred callback time is missing.");
  }

  normalized = {
    call_id: firstValue(retellCall.call_id, retellCall.id, body.call_id),
    caller_name: firstValue(caller.name, retellCall.caller_name, analysis.caller_name),
    caller_phone: firstValue(caller.phone, retellCall.caller_phone),
    caller_email: cleanLower(firstValue(caller.email, retellCall.caller_email, analysis.caller_email)),
    company: firstValue(caller.company, retellCall.company, analysis.company),
    call_intent: cleanLower(detectedIntent),
    urgency: cleanLower(detectedUrgency),
    callback_requested: callbackRequested,
    preferred_callback_time: preferredCallbackTime,
    transcript,
    summary,
    call_started_at: firstValue(retellCall.call_started_at, retellCall.started_at, retellCall.start_timestamp),
    call_duration_seconds: getRetellDuration(retellCall),
    voice_platform: "synthetic_retell_style",
    call_status: cleanLower(firstValue(retellCall.call_status, retellCall.status, "unknown"))
  };

  adapter_status = adapter_warnings.length > 0 ? "normalized_with_warnings" : "normalized";
}

return {
  json: {
    raw: body,
    source_provider,
    adapter_status,
    adapter_warnings,
    original_event_type,
    call: {
      call_id: cleanString(normalized.call_id),
      caller_name: cleanString(normalized.caller_name),
      caller_phone: cleanString(normalized.caller_phone),
      caller_email: cleanLower(normalized.caller_email),
      company: cleanString(normalized.company),
      call_intent: cleanLower(normalized.call_intent),
      urgency: cleanLower(normalized.urgency),
      callback_requested: toBoolean(normalized.callback_requested),
      preferred_callback_time: cleanString(normalized.preferred_callback_time),
      transcript: cleanString(normalized.transcript),
      summary: cleanString(normalized.summary),
      call_started_at: cleanString(normalized.call_started_at),
      call_duration_seconds: toNumber(normalized.call_duration_seconds),
      voice_platform: cleanLower(normalized.voice_platform),
      call_status: cleanLower(normalized.call_status)
    }
  }
};

const call = $json.call;
const errors = [];
const warnings = [];

function hasValue(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

if (!hasValue(call.call_id)) {
  errors.push("Missing call_id");
}

if (
  !hasValue(call.caller_name) &&
  !hasValue(call.caller_phone) &&
  !hasValue(call.caller_email)
) {
  errors.push("Missing caller identity");
}

if (
  !hasValue(call.call_intent) &&
  !hasValue(call.summary) &&
  !hasValue(call.transcript)
) {
  errors.push("Missing call intent, summary, or transcript");
}

if (!hasValue(call.voice_platform)) {
  errors.push("Missing voice_platform");
}

if (!hasValue(call.call_status)) {
  warnings.push("Missing call_status");
}

if (
  hasValue(call.caller_email) &&
  !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(call.caller_email)
) {
  warnings.push("caller_email format looks invalid");
}

if (
  call.call_duration_seconds !== null &&
  call.call_duration_seconds < 0
) {
  errors.push("call_duration_seconds cannot be negative");
}

if (
  hasValue(call.call_started_at) &&
  Number.isNaN(Date.parse(call.call_started_at))
) {
  warnings.push("call_started_at is not a valid timestamp");
}

const validation_status = errors.length > 0 ? "invalid" : "valid";

return {
  json: {
    ...$json,
    validation: {
      status: validation_status,
      errors,
      warnings
    }
  }
};

const call = $json.call;
const validation = $json.validation ?? { status: "valid", errors: [], warnings: [] };

const intentText = [
  call.call_intent,
  call.summary,
  call.transcript
].filter(Boolean).join(" ").toLowerCase();

const urgencyText = [
  call.urgency,
  call.summary,
  call.transcript
].filter(Boolean).join(" ").toLowerCase();

function includesAny(text, keywords) {
  return keywords.some((keyword) => text.includes(keyword));
}

const keywordGroups = {
  emergency: [
    "emergency",
    "urgent",
    "critical",
    "immediately",
    "asap",
    "system down",
    "is down",
    "outage",
    "cannot operate",
    "can't operate",
    "business stopped"
  ],
  sales: [
    "sales",
    "pricing",
    "quote",
    "demo",
    "proposal",
    "buy",
    "purchase",
    "consultation",
    "new service"
  ],
  support: [
    "support",
    "help",
    "issue",
    "problem",
    "broken",
    "not working",
    "technical",
    "error",
    "bug"
  ],
  billing: [
    "billing",
    "invoice",
    "payment",
    "charge",
    "refund",
    "subscription",
    "receipt"
  ],
  general: [
    "general",
    "question",
    "information",
    "follow up",
    "checking in"
  ]
};

let intent = "general";
let intent_reason = "Defaulted to general inquiry.";

if (includesAny(intentText, keywordGroups.emergency)) {
  intent = "emergency";
  intent_reason = "Emergency keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.sales)) {
  intent = "sales";
  intent_reason = "Sales keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.billing)) {
  intent = "billing";
  intent_reason = "Billing keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.support)) {
  intent = "support";
  intent_reason = "Support keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.general)) {
  intent = "general";
  intent_reason = "General inquiry keywords found in call content.";
}

let urgency = "low";
let urgency_reason = "Defaulted to low urgency.";

if (
  call.urgency === "emergency" ||
  includesAny(urgencyText, keywordGroups.emergency)
) {
  urgency = "emergency";
  urgency_reason = "Emergency urgency signal found.";
} else if (
  call.urgency === "high" ||
  includesAny(urgencyText, ["urgent", "asap", "today", "immediately"])
) {
  urgency = "high";
  urgency_reason = "High urgency signal found.";
} else if (
  call.urgency === "medium" ||
  includesAny(urgencyText, ["soon", "this week", "follow up"])
) {
  urgency = "medium";
  urgency_reason = "Medium urgency signal found.";
}

let route_key = "general_queue";

if (validation.status !== "valid") {
  route_key = "manual_review";
} else if (intent === "emergency" || urgency === "emergency" || urgency === "high") {
  route_key = "urgent_human_review";
} else if (intent === "sales") {
  route_key = "sales_follow_up";
} else if (intent === "support") {
  route_key = "support_queue";
} else if (intent === "billing") {
  route_key = "billing_queue";
}

return {
  json: {
    ...$json,
    classification: {
      intent,
      urgency,
      intent_reason,
      urgency_reason
    },
    routing: {
      route_key
    }
  }
};

const call = $json.call;
const validation = $json.validation;
const classification = $json.classification;
const routing = $json.routing;
const routeHandler = $json.route_handler;

function hasValue(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

return {
  json: {
    ...$json,
    call_log: {
      event_type: "ai_voice_call_routed",
      workflow_name: "AI Voice Ops Router",
      call_id: call.call_id,
      voice_platform: call.voice_platform,
      call_status: call.call_status,
      caller: {
        name: call.caller_name,
        company: call.company,
        phone_present: hasValue(call.caller_phone),
        email_present: hasValue(call.caller_email)
      },
      classification: {
        intent: classification.intent,
        urgency: classification.urgency,
        intent_reason: classification.intent_reason,
        urgency_reason: classification.urgency_reason
      },
      routing: {
        route_key: routing.route_key,
        route_name: routeHandler.route_name,
        owner_queue: routeHandler.owner_queue,
        priority: routeHandler.priority,
        sla: routeHandler.sla,
        notification_required: routeHandler.notification_required
      },
      validation: {
        status: validation.status,
        errors: validation.errors,
        warnings: validation.warnings
      },
      call: {
        started_at: call.call_started_at,
        duration_seconds: call.call_duration_seconds,
        callback_requested: call.callback_requested,
        preferred_callback_time: call.preferred_callback_time
      },
      summary: call.summary,
      processed_at: new Date().toISOString()
    }
  }
};

parameters.responseBody:
={{
{
  success: $json.validation.status === "valid",
  call_id: $json.call.call_id || null,
  route: $json.routing.route_key,
  route_name: $json.route_handler.route_name,
  classification: {
    intent: $json.classification.intent,
    urgency: $json.classification.urgency
  },
  validation_status: $json.validation.status,
  errors: $json.validation.errors,
  warnings: $json.validation.warnings,
  message: $json.validation.status === "valid"
    ? "Call received and routed."
    : "Call payload requires manual review."
}
}}
